import json
from pathlib import Path

REQUIRED = ["gate", "receipt_type", "source", "captured_at_utc", "status", "evidence_ref", "commit_sha"]
RECEIPTS = [
    Path("governance/proofs/external/telegram/production_receipt.json"),
    Path("governance/proofs/external/runtime/live_runtime_receipt.json"),
    Path("governance/proofs/external/claude/external_claude_audit_result.json"),
]

def validate_one(path: Path) -> dict:
    if not path.exists():
        return {"path": str(path), "status": "missing"}
    data = json.loads(path.read_text(encoding="utf-8"))
    missing = [x for x in REQUIRED if x not in data]
    if missing:
        return {"path": str(path), "status": "invalid", "missing": missing}
    if data.get("commit_sha") in (None, "", "null"):
        return {"path": str(path), "status": "invalid", "missing": ["non_null_commit_sha"]}
    return {"path": str(path), "status": "valid"}

def main() -> int:
    results = [validate_one(p) for p in RECEIPTS]
    print(json.dumps({"release_pass": False, "results": results}, ensure_ascii=False, indent=2))
    if any(r["status"] != "valid" for r in results):
        raise SystemExit(1)
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
